      weekTitle,
      nextWeekTitle,
      memberName,
      analysisResults,
      dailyLogs,
      nextWeekPlan,
      tasksMap,
      startDate,
      endDate
    });

    // canvases.edit API는 권한 제약이 심하므로, 설정된 정현웅 님의 유저 토큰이 존재할 경우 유저 권한으로 실행합니다.
